from flask import Flask, request, jsonify, url_for
from itsdangerous import URLSafeTimedSerializer
from flask_mail import Mail, Message
from werkzeug.security import generate_password_hash, check_password_hash
import os

app = Flask(__name__)

# Configuration for email
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your-email@example.com'
app.config['MAIL_PASSWORD'] = 'your-email-password'
app.config['SECRET_KEY'] = 'your-secret-key'
app.config['SECURITY_PASSWORD_SALT'] = 'your-password-salt'

mail = Mail(app)
serializer = URLSafeTimedSerializer(app.config['SECRET_KEY'])

# Mock database
users_db = {
    'user@example.com': {
        'password': generate_password_hash('securepassword'),
        'mfa_enabled': True
    }
}

def send_reset_email(email, token):
    msg = Message('Reset MFA', sender='noreply@example.com', recipients=[email])
    link = url_for('reset_mfa_token', token=token, _external=True)
    msg.body = f'Click the link to reset your MFA settings: {link}'
    mail.send(msg)

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.json.get('email')
    if not email or email not in users_db:
        return jsonify({'error': 'Invalid email'}), 400

    token = serializer.dumps(email, salt=app.config['SECURITY_PASSWORD_SALT'])
    send_reset_email(email, token)
    return jsonify({'message': 'Reset link sent to your email'}), 200

@app.route('/reset-mfa/<token>', methods=['GET'])
def reset_mfa_token(token):
    try:
        email = serializer.loads(token, salt=app.config['SECURITY_PASSWORD_SALT'], max_age=3600)
    except:
        return jsonify({'error': 'Invalid or expired token'}), 400

    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        return jsonify({'message': 'MFA has been disabled. You can now log in with your password.'}), 200
    return jsonify({'error': 'User not found'}), 404

